#include <cassert>
#include <iostream>

// given -- do not modify
class DynamicArray {
    int* m_data{};
    int m_size{};
    int m_capacity{};

public:
    DynamicArray(int capacity)
        : m_data{ new int[static_cast<std::size_t>(capacity)]{} }
        , m_capacity{ capacity }
    {
    }

    ~DynamicArray() { delete[] m_data; }

    void push_back(int val)
    {
        assert(m_size < m_capacity);
        m_data[m_size++] = val;
    }

    void resize(int newCap)
    {
        int* newData{ new int[static_cast<std::size_t>(newCap)]{} };
        int copyCount{ (m_size < newCap) ? m_size : newCap };
        for (int i{ 0 }; i < copyCount; ++i)
            newData[i] = m_data[i];
        delete[] m_data;
        m_data = newData;
        m_capacity = newCap;
        if (m_size > newCap)
            m_size = newCap;
    }

    int size() const { return m_size; }
    int get(int index) const
    {
        assert(index >= 0 && index < m_size);
        return m_data[index];
    }
};

// TODO: define class FixedArray that publicly inherits from DynamicArray
//       (header:  class FixedArray : public DynamicArray ).
//   - TODO: write the constructor (const int* data, int count): pass count up
